   453→  Future<void> startRecording({
   454→    required BuildContext context,
   455→    required WidgetRef ref,
   456→    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
   457→    required ValueNotifier<int> recordingTimerCount,
   458→    required ValueNotifier<bool> isRecording,
   459→    required ObjectRef<Timer?> recordingTimer,
   460→  }) async {
   461→    await ref.read(cameraControllerProvider.notifier).startRecording();
   462→
   463→    recordingTimerCount.value = 0;
   464→    recordingTimer.value = Timer.periodic(
   465→      const Duration(milliseconds: 1000),
   466→      (Timer timer) {
   467→        recordingTimerCount.value += 1;
   468→
   469→        final analysisType = ref.watch(
   470→          cameraControllerProvider.select((value) => value.analysisType),
   471→        );
   472→
   473→        final threshold = [AnalysisType.pitchingAll, AnalysisType.hittingAll]
   474→                .contains(analysisType)
   475→            ? 120
   476→            : 10;
   477→        if (recordingTimerCount.value >= threshold) {
   478→          stopRecording(
   479→            context: context,
   480→            ref: ref,
   481→            recordingTimerCount: recordingTimerCount,
   482→            isRecording: isRecording,
   483→            recordingTimer: recordingTimer,
   484→            currentOrientation: currentOrientation,
   485→          );
   486→        }
   487→      },
   488→    );
   489→
   490→    isRecording.value = true;
   491→  }
   492→
   493→  Future<void> stopRecording({
   494→    required BuildContext context,
   495→    required WidgetRef ref,
   496→    required ValueNotifier<int> recordingTimerCount,
   497→    required ValueNotifier<bool> isRecording,
   498→    required ObjectRef<Timer?> recordingTimer,
   499→    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
   500→  }) async {
   501→    recordingTimer.value!.cancel();
   502→    recordingTimer.value = null;
   503→
   504→    // NOTE: _cameraController.stopRecording causes a delay to save a video file.
   505→
   506→    // NOTE: Use `listenProviderWithLoadingDialogAndSnackbar` normally to show a loading dialog.
   507→    // But it is difficult to use the method for only a specific method of a provider.
   508→    final dialog = showLoadingDialog(context: context);
   509→    final recordedVideoData = await ref
   510→        .read(cameraControllerProvider.notifier)
   511→        .stopRecordingAndSaveToLocalStorage(
   512→          ref.read(appUnitProvider),
   513→        );
   514→    if (context.mounted) {
   515→      await popLoadingDialog(context: context, dialog: dialog);
   516→    }
   517→
   518→    ref.read(uploadQueueProvider).addUploadTask(recordedVideoData);
   519→
   520→    ScreenOrientation.setDefault();
   521→    recordingTimerCount.value = 0;
   522→    isRecording.value = false;
   523→  }
   524→
   525→  Future<void> tapRecordingButton({
   526→    required BuildContext context,
   527→    required WidgetRef ref,
   528→    required ValueNotifier<bool> isRecording,
   529→    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
   530→    required ValueNotifier<int> recordingTimerCount,
   531→    required ObjectRef<Timer?> recordingTimer,
   532→  }) async {
   533→    if (isRecording.value) {
   534→      await stopRecording(
   535→        context: context,
   536→        ref: ref,
   537→        recordingTimerCount: recordingTimerCount,
   538→        isRecording: isRecording,
   539→        recordingTimer: recordingTimer,
   540→        currentOrientation: currentOrientation,
   541→      );
   542→    } else {
   543→      await startRecording(
   544→        context: context,
   545→        ref: ref,
   546→        currentOrientation: currentOrientation,
   547→        recordingTimerCount: recordingTimerCount,
   548→        recordingTimer: recordingTimer,
   549→        isRecording: isRecording,
   550→      );
   551→    }
   552→  }
