   577→/// Absorbs screen rotation and forces the child to always be drawn
   578→/// as if in normal Portrait orientation (portraitUp).
   579→class _OrientationAbsorber extends StatelessWidget {
   580→  final Widget child;
   581→  final ValueChanged<NativeDeviceOrientation>? onOrientationChanged;
   582→
   583→  const _OrientationAbsorber({
   584→    required this.child,
   585→    this.onOrientationChanged,
   586→  });
   587→
   588→  @override
   589→  Widget build(BuildContext context) {
   590→    return NativeDeviceOrientationReader(
   591→      builder: (context) {
   592→        final orientation = NativeDeviceOrientationReader.orientation(context);
   593→        if (onOrientationChanged != null) {
   594→          onOrientationChanged!(orientation);
   595→        }
   596→
   597→        final turns = {
   598→          NativeDeviceOrientation.unknown: 0,
   599→          NativeDeviceOrientation.portraitUp: 0,
   600→          NativeDeviceOrientation.landscapeRight: 1,
   601→          NativeDeviceOrientation.portraitDown: 2,
   602→          NativeDeviceOrientation.landscapeLeft: 3,
   603→        }[orientation]!;
   604→
   605→        final original = MediaQuery.of(context);
   606→        final modified = original.copyWith(
   607→          size: _rotateSize(original.size, turns),
   608→          padding: _rotateEdgeInsets(original.padding, turns),
   609→          viewPadding: _rotateEdgeInsets(original.viewPadding, turns),
   610→          viewInsets: _rotateEdgeInsets(original.viewInsets, turns),
   611→          systemGestureInsets:
   612→              _rotateEdgeInsets(original.systemGestureInsets, turns),
   613→        );
   614→
   615→        return RotatedBox(
   616→          quarterTurns: turns,
   617→          child: MediaQuery(
   618→            data: modified,
   619→            child: child,
   620→          ),
   621→        );
   622→      },
   623→    );
   624→  }
   625→
   626→  Size? _rotateSize(Size? src, int turns) {
   627→    if (src == null) {
   628→      return null;
   629→    }
   630→    return turns % 2 == 1 ? src.flipped : src;
   631→  }
   632→
   633→  EdgeInsets _rotateEdgeInsets(EdgeInsets src, int turns) {
   634→    switch (turns % 4) {
   635→      case 0:
   636→        return src;
