  }

  Widget _buildHittingMetrics(
    BuildContext context,
    Ball ball,
    UnitType unitType,
    ValueNotifier<NativeDeviceOrientation> orientation,
  ) {
    return ValueListenableBuilder<NativeDeviceOrientation>(
      valueListenable: orientation,
      builder: (context, currentOrientation, child) {
        if (currentOrientation == NativeDeviceOrientation.landscapeLeft) {
          return Row(
            children: [
              Expanded(child: Container()),
              const Gap(6),
              Expanded(
                child: _buildMetricBadgeForLandscape(
                  context.l10n.session_details_page__angle,
                  UnitConverter.formatAngle(ball.angle),
                  ColorManager.angle,
                  orientation,
                ),
              ),
              const Gap(6),
              // Use 2 out of 4 divisions to match the same width as pitching
              Expanded(
                child: _buildMetricBadgeForLandscape(
                  context.l10n.session_details_page__exit_velocity,
                  UnitConverter.formatVelocity(ball.exitVelocity, unitType),
                  ColorManager.exitVelocity,
                  orientation,
                ),
              ),
              const Gap(6),
              Expanded(child: Container()),
            ],
          );
        } else if (currentOrientation ==
            NativeDeviceOrientation.landscapeRight) {
          return Row(
            children: [
              Expanded(child: Container()),
              const Gap(6),
              // Use 2 out of 4 divisions to match the same width as pitching
              Expanded(
                child: _buildMetricBadgeForLandscape(
                  context.l10n.session_details_page__exit_velocity,
                  UnitConverter.formatVelocity(ball.exitVelocity, unitType),
                  ColorManager.exitVelocity,
                  orientation,
                ),
              ),
              const Gap(6),
              Expanded(
                child: _buildMetricBadgeForLandscape(
                  context.l10n.session_details_page__angle,
                  UnitConverter.formatAngle(ball.angle),
                  ColorManager.angle,
                  orientation,
                ),
              ),
              const Gap(6),
              Expanded(child: Container()),
            ],
          );
        } else {
          // In portrait mode, keep the original horizontal layout
          return Row(
            children: [
              Expanded(child: Container()),
              const Gap(6),
              // Use 2 out of 4 divisions to match the same width as pitching
              Expanded(
                child: _buildMetricBadge(
                  context.l10n.session_details_page__exit_velocity,
                  UnitConverter.formatVelocity(ball.exitVelocity, unitType),
                  ColorManager.exitVelocity,
                  orientation,
                ),
              ),
              const Gap(6),
              Expanded(
                child: _buildMetricBadge(
                  context.l10n.session_details_page__angle,
                  UnitConverter.formatAngle(ball.angle),
                  ColorManager.angle,
                  orientation,
                ),
              ),
              const Gap(6),
              Expanded(child: Container()),
            ],
          );
        }
      },
    );
  }

  Widget _buildMetricBadge(
    String name,
    ValueAndUnit valueAndUnit,
